"""Throwaway: pull live Langfuse Concierge prompts via SDK directly.

Avoids importing the repo's agents.* packages (they have heavy import-time
side effects). Replicates the @@@langfusePrompt:...@@@ reference resolution.
"""

from __future__ import annotations

import os
import re

from langfuse import Langfuse

_REF = re.compile(r"@@@langfusePrompt:name=([^|]+)\|label=([^@]+)@@@")

_VARIABLES = {
    "default_terminal_url": "http://localhost:7681/",
    "demo_terminal_base_url": "https://demo.rebase.ai/terminal",
}


def _client() -> Langfuse:
    return Langfuse(
        public_key=os.environ["LANGFUSE_PUBLIC_KEY"],
        secret_key=os.environ["LANGFUSE_SECRET_KEY"],
        host=os.environ["LANGFUSE_BASE_URL"].rstrip("/"),
    )


def _fetch(client: Langfuse, name: str, label: str) -> str:
    prompt = client.get_prompt(name, label=label, cache_ttl_seconds=0)
    try:
        return prompt.compile(**_VARIABLES)
    except Exception:  # noqa: BLE001 - some prompts have no vars
        return prompt.prompt if isinstance(prompt.prompt, str) else str(prompt.prompt)


def _resolve(client: Langfuse, body: str, label: str, depth: int = 0) -> str:
    if depth > 5:
        return body

    def repl(m: re.Match[str]) -> str:
        sub_name = m.group(1).strip()
        sub_label = m.group(2).strip() or label
        sub = _fetch(client, sub_name, sub_label)
        return _resolve(client, sub, sub_label, depth + 1)

    return _REF.sub(repl, body)


def _banner(title: str) -> None:
    print("\n" + "=" * 90)
    print(title)
    print("=" * 90, flush=True)


def main() -> None:
    label = os.environ.get("LANGFUSE_PROMPT_LABEL", "production")
    client = _client()
    print(f"label={label!r} host={os.environ['LANGFUSE_BASE_URL']}", flush=True)

    names = [
        "ux/concierge-router",
        "ux/concierge",
        "rebaseai/concierge/spine",
        "rebaseai/concierge/stage-router",
        "rebaseai/concierge/idle",
        "rebaseai/concierge/side_question",
        "rebaseai/discovery/mechanics",
        "rebaseai/discovery/spine",
        "rebaseai/discovery/stage/idle",
    ]

    for name in names:
        try:
            raw = _fetch(client, name, label)
        except Exception as exc:  # noqa: BLE001 - debug
            _banner(f"{name}  ->  ERROR")
            print(repr(exc), flush=True)
            continue
        _banner(f"{name}  (RAW)")
        print(raw, flush=True)
        if _REF.search(raw):
            _banner(f"{name}  (RESOLVED)")
            print(_resolve(client, raw, label), flush=True)


if __name__ == "__main__":
    main()

"""Throwaway reproduction: replay the exact Concierge router request to multiple LLMs.

Rebuilds the request that produced the mis-route on the "ok" turn of session
4ffc1a6b-61e0-43bf-9e8b-ec48b07db95e:

    system  = exact persisted system message (Agno preamble + Langfuse router
              prompt + workflow state + memories + session_state)
    history = the 9 leader messages from the 3 prior turns (hi / repo / yes),
              each: user(input) -> assistant(delegate_task_to_member) -> tool(result)
    user    = "ok"

Then asks each model to choose, with the delegate_task_to_member tool available.
Reports the member_id each model routes to (and any prose it emits first).

Faithful-decision test, not byte-identical transport: OpenAI runtime uses the
Responses API; here we use chat.completions for cross-provider comparison.
"""

from __future__ import annotations

import json
import os
import subprocess
from collections import Counter
from typing import Any

SESSION_ID = "4ffc1a6b-61e0-43bf-9e8b-ec48b07db95e"
TEAM_RUN_ID = "d459ff43-055a-444f-9b78-8b93dde47887"
PRIOR_TURNS = [  # (team_run_id, user_input)
    ("24b194ba-1eab-4d68-a1a2-02ceff679de6", None),
    ("411aea49-c587-4367-8e57-99e140931943", None),
    ("c91d9b73-cba8-41fd-9d45-52597605f6bf", None),
]
CURRENT_INPUT = "ok"
RUNS_PER_MODEL = 5

DELEGATE_TOOL = {
    "type": "function",
    "function": {
        "name": "delegate_task_to_member",
        "description": (
            "Use this function to delegate a task to the selected team member."
        ),
        "parameters": {
            "type": "object",
            "properties": {
                "member_id": {
                    "type": "string",
                    "description": (
                        "The ID of the member to delegate the task to. Use only "
                        "the ID of the member, not the ID of the team followed by "
                        "the ID of the member."
                    ),
                },
                "task": {"type": "string", "description": "The task to delegate."},
            },
            "required": ["member_id", "task"],
        },
    },
}


def _load_runs() -> list[dict[str, Any]]:
    raw = subprocess.check_output(
        [
            "docker", "exec", "agentos-db", "psql", "-U", "ai", "-d", "ai",
            "-t", "-A", "-c",
            f"SELECT runs FROM agno_sessions WHERE session_id='{SESSION_ID}';",
        ],
        text=True,
    )
    return json.loads(raw)


def _run_by_id(runs: list[dict[str, Any]], run_id: str) -> dict[str, Any]:
    return next(r for r in runs if r.get("run_id") == run_id)


def _delegate_args(run: dict[str, Any]) -> tuple[str, str]:
    """Pull member_id/task from the leader's delegate tool call in this run."""
    for ev in run.get("events") or []:
        if not isinstance(ev, dict):
            continue
        tool = ev.get("tool") or {}
        if isinstance(tool, dict) and tool.get("tool_name") == "delegate_task_to_member":
            args = tool.get("tool_args") or {}
            return args.get("member_id", "concierge-agent"), args.get("task", "")
    # Fallback: parse from messages
    for m in run.get("messages") or []:
        for tc in m.get("tool_calls") or []:
            fn = tc.get("function") or {}
            if fn.get("name") == "delegate_task_to_member":
                a = json.loads(fn.get("arguments") or "{}")
                return a.get("member_id", "concierge-agent"), a.get("task", "")
    return "concierge-agent", ""


def build_messages(runs: list[dict[str, Any]]) -> list[dict[str, Any]]:
    cur = _run_by_id(runs, TEAM_RUN_ID)
    system = cur["messages"][0]["content"]
    assert cur["messages"][0]["role"] == "system"

    messages: list[dict[str, Any]] = [{"role": "system", "content": system}]

    for idx, (rid, _) in enumerate(PRIOR_TURNS):
        run = _run_by_id(runs, rid)
        user_input = run.get("input", {})
        if isinstance(user_input, dict):
            user_input = user_input.get("input_content", "")
        member_id, task = _delegate_args(run)
        member_response = run.get("content") or ""
        call_id = f"call_hist_{idx}"
        messages.append({"role": "user", "content": str(user_input)})
        messages.append(
            {
                "role": "assistant",
                "content": None,
                "tool_calls": [
                    {
                        "id": call_id,
                        "type": "function",
                        "function": {
                            "name": "delegate_task_to_member",
                            "arguments": json.dumps(
                                {"member_id": member_id, "task": task}
                            ),
                        },
                    }
                ],
            }
        )
        messages.append(
            {"role": "tool", "tool_call_id": call_id, "content": str(member_response)}
        )

    messages.append({"role": "user", "content": CURRENT_INPUT})
    return messages


def _summarize_openai(resp: Any) -> str:
    msg = resp.choices[0].message
    prose = (msg.content or "").strip()
    tcs = msg.tool_calls or []
    if tcs:
        a = json.loads(tcs[0].function.arguments or "{}")
        member = a.get("member_id", "?")
        return f"delegate->{member}" + (f"  [prose: {prose[:60]!r}]" if prose else "")
    return f"NO_DELEGATE  [prose: {prose[:80]!r}]"


def _summarize_anthropic(resp: Any) -> str:
    member = None
    prose_parts = []
    for block in resp.content:
        if block.type == "tool_use" and block.name == "delegate_task_to_member":
            member = block.input.get("member_id", "?")
        elif block.type == "text":
            prose_parts.append(block.text)
    prose = " ".join(prose_parts).strip()
    if member:
        return f"delegate->{member}" + (f"  [prose: {prose[:60]!r}]" if prose else "")
    return f"NO_DELEGATE  [prose: {prose[:80]!r}]"


def run_openai(model: str, messages: list[dict[str, Any]]) -> None:
    from openai import OpenAI

    client = OpenAI(api_key=os.environ["OPENAI_API_KEY"])
    print(f"\n### OpenAI {model}")
    results: Counter[str] = Counter()
    for _ in range(RUNS_PER_MODEL):
        try:
            resp = client.chat.completions.create(
                model=model,
                messages=messages,
                tools=[DELEGATE_TOOL],
                tool_choice="auto",
            )
        except Exception as exc:  # noqa: BLE001 - debug
            print(f"  ERROR: {exc}")
            return
        s = _summarize_openai(resp)
        results[s] += 1
        print(f"  {s}")
    print(f"  -> {dict(results)}")


def run_anthropic(model: str, messages: list[dict[str, Any]]) -> None:
    from anthropic import Anthropic

    client = Anthropic(api_key=os.environ["ANTHROPIC_API_KEY"])
    system = messages[0]["content"]
    conv: list[dict[str, Any]] = []
    for m in messages[1:]:
        if m["role"] == "user":
            conv.append({"role": "user", "content": m["content"]})
        elif m["role"] == "assistant" and m.get("tool_calls"):
            tc = m["tool_calls"][0]
            args = json.loads(tc["function"]["arguments"])
            conv.append(
                {
                    "role": "assistant",
                    "content": [
                        {
                            "type": "tool_use",
                            "id": tc["id"],
                            "name": "delegate_task_to_member",
                            "input": args,
                        }
                    ],
                }
            )
        elif m["role"] == "tool":
            conv.append(
                {
                    "role": "user",
                    "content": [
                        {
                            "type": "tool_result",
                            "tool_use_id": m["tool_call_id"],
                            "content": m["content"],
                        }
                    ],
                }
            )
    a_tool = {
        "name": "delegate_task_to_member",
        "description": DELEGATE_TOOL["function"]["description"],
        "input_schema": DELEGATE_TOOL["function"]["parameters"],
    }
    print(f"\n### Anthropic {model}")
    results: Counter[str] = Counter()
    for _ in range(RUNS_PER_MODEL):
        try:
            resp = client.messages.create(
                model=model,
                max_tokens=512,
                system=system,
                messages=conv,
                tools=[a_tool],
            )
        except Exception as exc:  # noqa: BLE001 - debug
            print(f"  ERROR: {exc}")
            return
        s = _summarize_anthropic(resp)
        results[s] += 1
        print(f"  {s}")
    print(f"  -> {dict(results)}")


def main() -> None:
    runs = _load_runs()
    messages = build_messages(runs)
    print(f"Reconstructed {len(messages)} messages (system + {len(messages) - 2} history + 'ok').")
    print(f"Current user input: {CURRENT_INPUT!r}")
    print(f"Expected per router rule 1: delegate->discovery-agent")
    print(f"Actual in production:       delegate->concierge-agent\n")

    for model in ("gpt-5.4", "gpt-5.5", "gpt-4o"):
        run_openai(model, messages)

    for model in ("claude-sonnet-4-5-20250929",):
        run_anthropic(model, messages)


if __name__ == "__main__":
    main()

