def _to_responses_input(messages: list[dict[str, Any]]) -> tuple[str, list[dict[str, Any]]]:
    """Convert chat messages to Responses API (instructions, input items)."""
    instructions = messages[0]["content"]
    items: list[dict[str, Any]] = []
    for m in messages[1:]:
        if m["role"] == "user":
            items.append({"role": "user", "content": m["content"]})
        elif m["role"] == "assistant" and m.get("tool_calls"):
            tc = m["tool_calls"][0]
            items.append(
                {
                    "type": "function_call",
                    "call_id": tc["id"],
                    "name": "delegate_task_to_member",
                    "arguments": tc["function"]["arguments"],
                }
            )
        elif m["role"] == "tool":
            items.append(
                {
                    "type": "function_call_output",
                    "call_id": m["tool_call_id"],
                    "output": m["content"],
                }
            )
    return instructions, items


def run_openai_responses(model: str, messages: list[dict[str, Any]]) -> None:
    from openai import OpenAI

    client = OpenAI(api_key=os.environ["OPENAI_API_KEY"])
    instructions, items = _to_responses_input(messages)
    r_tool = {
        "type": "function",
        "name": "delegate_task_to_member",
        "description": DELEGATE_TOOL["function"]["description"],
        "parameters": DELEGATE_TOOL["function"]["parameters"],
    }
    print(f"\n### OpenAI Responses API {model}")
    results: Counter[str] = Counter()
    for _ in range(RUNS_PER_MODEL):
        try:
            resp = client.responses.create(
                model=model,
                instructions=instructions,
                input=items,
                tools=[r_tool],
                tool_choice="auto",
            )
