                        prose_parts.append(c.text)
        prose = " ".join(prose_parts).strip()
        s = (f"delegate->{member}" if member else "NO_DELEGATE") + (
            f"  [prose: {prose[:60]!r}]" if prose else ""
        )
        results[s] += 1
        print(f"  {s}")
    print(f"  -> {dict(results)}")


